#!/usr/bin/env python3\n\"\"\"\nTracePort Advanced Demo\nDemonstrates advanced scanning scenarios and techniques\n\"\"\"\n\nfrom traceport.scanner import PortScanner\nfrom traceport.utils import validate_ip, parse_port_range, is_valid_port_range\nimport json\nfrom collections import Counter\nimport time\n\ndef print_section(title):\n    print(\"\\n\" + \"=\"*70)\n    print(f\"  {title}\")\n    print(\"=\"*70 + \"\\n\")\n\ndef demo_service_fingerprinting():\n    \"\"\"Demo: Identify running services and versions\"\"\"\n    print_section(\"Advanced Demo 1: Service Fingerprinting\")\n    \n    scanner = PortScanner(max_threads=150, timeout=2, banner_grab=True)\n    \n    print(\"Scanning localhost with banner grabbing enabled...\")\n    print(\"This will attempt to identify service versions.\\n\")\n    \n    result = scanner.scan(\"localhost\", port_range=\"1-1000\")\n    \n    if result.services:\n        print(f\"Found {len(result.services)} services:\\n\")\n        \n        # Group by service name\n        services_grouped = {}\n        for svc in result.services:\n            if svc.service_name not in services_grouped:\n                services_grouped[svc.service_name] = []\n            services_grouped[svc.service_name].append(svc)\n        \n        # Display grouped services\n        for service_name, services in sorted(services_grouped.items()):\n            print(f\"Service: {service_name.upper()}\")\n            for svc in services:\n                print(f\"  Port {svc.port:5} | Version: {svc.version or 'Unknown':15} | Banner: {svc.banner[:40] if svc.banner else 'N/A'}...\")\n            print()\n        \n        # Vulnerability risk assessment\n        print(\"\\nPotential Security Findings:\")\n        print(\"-\" * 70)\n        \n        vulnerable_services = []\n        for svc in result.services:\n            if svc.banner:\n                banner_lower = svc.banner.lower()\n                if 'apache/2.4.1' in banner_lower or 'apache/2.4.0' in banner_lower:\n                    vulnerable_services.append((svc.port, svc.service_name, \"Outdated Apache\"))\n                if 'openssh_3.9' in banner_lower or 'openssh_4.0' in banner_lower:\n                    vulnerable_services.append((svc.port, svc.service_name, \"Outdated OpenSSH\"))\n        \n        if vulnerable_services:\n            print(\"Potentially vulnerable services detected:\")\n            for port, service, issue in vulnerable_services:\n                print(f\"  • Port {port}: {service} - {issue}\")\n        else:\n            print(\"✓ No known vulnerable services detected\")\n    else:\n        print(\"No services found with banner information\")\n    \n    return result\n\ndef demo_network_topology():\n    \"\"\"Demo: Map network services and ports\"\"\"\n    print_section(\"Advanced Demo 2: Network Service Topology\")\n    \n    # Common port groupings\n    port_groups = {\n        'Web Services': [80, 443, 8080, 8443, 3000, 5000],\n        'Database Services': [3306, 5432, 27017, 6379, 1433],\n        'SSH/Remote Access': [22, 3389, 5900],\n        'Mail Services': [25, 110, 143, 465, 587, 993, 995],\n        'DNS/Network': [53, 67, 68],\n    }\n    \n    scanner = PortScanner(max_threads=200, timeout=1, banner_grab=False)\n    \n    print(\"Scanning localhost for service categories...\\n\")\n    \n    result = scanner.scan(\"localhost\", port_range=\"1-65535\")\n    \n    # Map found ports to categories\n    open_port_set = set(result.open_ports)\n    \n    print(\"Service Topology Map:\")\n    print(\"-\" * 70)\n    \n    for category, ports in port_groups.items():\n        active = [p for p in ports if p in open_port_set]\n        status = \"✓\" if active else \"✗\"\n        print(f\"{status} {category:20} | Active: {active if active else 'None'}\")\n    \n    # Unclassified ports\n    classified_ports = set()\n    for ports in port_groups.values():\n        classified_ports.update(ports)\n    \n    unclassified = sorted([p for p in result.open_ports if p not in classified_ports])\n    if unclassified:\n        print(f\"\\nUnclassified Open Ports: {unclassified}\")\n    \n    return result\n\ndef demo_comparative_analysis():\n    \"\"\"Demo: Compare scans across different targets\"\"\"\n    print_section(\"Advanced Demo 3: Comparative Analysis\")\n    \n    targets = [\"localhost\", \"127.0.0.1\"]\n    scanner = PortScanner(max_threads=100, timeout=1.5, banner_grab=False)\n    \n    results = {}\n    \n    print(f\"Scanning {len(targets)} targets for comparison...\\n\")\n    \n    for target in targets:\n        print(f\"Scanning {target}...\")\n        result = scanner.scan(target, port_range=\"1-1000\")\n        results[target] = result\n    \n    print(\"\\nComparative Analysis Results:\")\n    print(\"-\" * 70)\n    print(f\"{'Target':<20} {'Open Ports':<15} {'Duration':<15} {'Status'}\")\n    print(\"-\" * 70)\n    \n    for target, result in results.items():\n        print(f\"{target:<20} {result.open_ports_count:<15} {result.scan_duration:<15.2f} {result.status}\")\n    \n    # Port overlap analysis\n    if len(results) >= 2:\n        target_list = list(results.keys())\n        ports1 = set(results[target_list[0]].open_ports)\n        ports2 = set(results[target_list[1]].open_ports)\n        \n        print(\"\\nPort Overlap Analysis:\")\n        print(\"-\" * 70)\n        print(f\"Common ports:     {ports1 & ports2}\")\n        print(f\"Only in {target_list[0]}:  {ports1 - ports2}\")\n        print(f\"Only in {target_list[1]}:  {ports2 - ports1}\")\n    \n    return results\n\ndef demo_vulnerability_assessment():\n    \"\"\"Demo: Security vulnerability assessment\"\"\"\n    print_section(\"Advanced Demo 4: Vulnerability Assessment\")\n    \n    scanner = PortScanner(max_threads=100, timeout=2, banner_grab=True)\n    \n    print(\"Performing vulnerability assessment scan...\\n\")\n    \n    result = scanner.scan(\"localhost\", port_range=\"1-1000\")\n    \n    # Risk assessment\n    risk_levels = {'high': 0, 'medium': 0, 'low': 0}\n    findings = []\n    \n    print(\"Vulnerability Assessment Results:\")\n    print(\"=\"*70)\n    \n    # Check for common vulnerabilities\n    for svc in result.services:\n        if svc.port < 1024:\n            # Low port numbers can be risky\n            if svc.port in [22, 23]:\n                risk_levels['medium'] += 1\n                findings.append({\n                    'port': svc.port,\n                    'service': svc.service_name,\n                    'risk': 'MEDIUM',\n                    'issue': 'SSH/Telnet exposed - ensure strong auth'\n                })\n            elif svc.port in [25, 110, 143]:\n                risk_levels['low'] += 1\n                findings.append({\n                    'port': svc.port,\n                    'service': svc.service_name,\n                    'risk': 'LOW',\n                    'issue': 'Mail service - verify configuration'\n                })\n        \n        if svc.port > 1024:\n            # Database ports\n            if svc.port in [3306, 5432, 27017]:\n                risk_levels['high'] += 1\n                findings.append({\n                    'port': svc.port,\n                    'service': svc.service_name,\n                    'risk': 'HIGH',\n                    'issue': 'Database exposed - should be firewall protected'\n                })\n    \n    if findings:\n        print(f\"\\nFound {len(findings)} potential security issues:\\n\")\n        \n        for i, finding in enumerate(findings, 1):\n            risk_color = \"🔴\" if finding['risk'] == 'HIGH' else \"🟡\" if finding['risk'] == 'MEDIUM' else \"🟢\"\n            print(f\"{i}. {risk_color} [{finding['risk']}] Port {finding['port']} ({finding['service']})\")\n            print(f\"   Issue: {finding['issue']}\\n\")\n        \n        print(\"\\nRisk Summary:\")\n        print(\"-\" * 70)\n        print(f\"High Risk:   {risk_levels['high']}\")\n        print(f\"Medium Risk: {risk_levels['medium']}\")\n        print(f\"Low Risk:    {risk_levels['low']}\")\n    else:\n        print(\"✓ No security vulnerabilities detected\")\n    \n    return result\n\ndef demo_performance_analysis():\n    \"\"\"Demo: Detailed performance metrics\"\"\"\n    print_section(\"Advanced Demo 5: Performance Analysis\")\n    \n    configurations = [\n        {'name': 'Light', 'threads': 25, 'timeout': 3, 'banner': False},\n        {'name': 'Standard', 'threads': 100, 'timeout': 2, 'banner': False},\n        {'name': 'Aggressive', 'threads': 250, 'timeout': 1, 'banner': False},\n    ]\n    \n    metrics = []\n    port_range = \"1-2000\"\n    \n    print(f\"Analyzing performance with port range: {port_range}\\n\")\n    \n    for config in configurations:\n        print(f\"Testing {config['name']} configuration...\")\n        \n        scanner = PortScanner(\n            max_threads=config['threads'],\n            timeout=config['timeout'],\n            banner_grab=config['banner']\n        )\n        \n        start_time = time.time()\n        result = scanner.scan(\"localhost\", port_range=port_range)\n        elapsed = time.time() - start_time\n        \n        # Calculate metrics\n        ports_per_sec = result.total_ports_scanned / elapsed if elapsed > 0 else 0\n        \n        metrics.append({\n            'config': config['name'],\n            'threads': config['threads'],\n            'timeout': config['timeout'],\n            'duration': elapsed,\n            'ports_scanned': result.total_ports_scanned,\n            'open_ports': result.open_ports_count,\n            'ports_per_sec': ports_per_sec,\n            'efficiency': (result.open_ports_count / result.total_ports_scanned * 100) if result.total_ports_scanned > 0 else 0\n        })\n    \n    # Display results\n    print(\"\\nPerformance Metrics:\")\n    print(\"=\"*70)\n    print(f\"{'Config':<12} {'Threads':<10} {'Duration':<12} {'Ports/Sec':<12} {'Efficiency'}\")\n    print(\"-\"*70)\n    \n    for m in metrics:\n        print(f\"{m['config']:<12} {m['threads']:<10} {m['duration']:<12.2f} {m['ports_per_sec']:<12.0f} {m['efficiency']:.1f}%\")\n    \n    # Recommendations\n    print(\"\\nPerformance Recommendations:\")\n    print(\"-\"*70)\n    \n    fastest = max(metrics, key=lambda x: x['ports_per_sec'])\n    most_efficient = max(metrics, key=lambda x: x['efficiency'])\n    \n    print(f\"✓ Fastest: {fastest['config']} ({fastest['ports_per_sec']:.0f} ports/sec)\")\n    print(f\"✓ Most Efficient: {most_efficient['config']} ({most_efficient['efficiency']:.1f}% hit rate)\")\n    \n    return metrics\n\ndef demo_batch_export():\n    \"\"\"Demo: Export results in multiple formats\"\"\"\n    print_section(\"Advanced Demo 6: Multi-Format Export\")\n    \n    scanner = PortScanner(max_threads=100, timeout=2, banner_grab=True)\n    \n    print(\"Performing scan for export demonstration...\\n\")\n    result = scanner.scan(\"localhost\", port_range=\"1-500\")\n    \n    # JSON export\n    print(\"1. JSON Export:\")\n    print(\"-\" * 70)\n    json_data = result.to_json()\n    print(f\"JSON Output (first 300 chars):\\n{json_data[:300]}...\\n\")\n    \n    # Dictionary export with statistics\n    print(\"2. Dictionary with Statistics:\")\n    print(\"-\" * 70)\n    result_dict = result.to_dict()\n    \n    stats = {\n        'target': result_dict['target'],\n        'ip_address': result_dict['ip_address'],\n        'total_scanned': result_dict['total_ports_scanned'],\n        'open_ports_count': result_dict['open_ports_count'],\n        'scan_duration': result_dict['scan_duration'],\n        'status': result_dict['status']\n    }\n    \n    print(json.dumps(stats, indent=2))\n    \n    # CSV format simulation\n    print(\"\\n3. CSV Format:\")\n    print(\"-\" * 70)\n    print(\"Port,Service,Version,Protocol,Banner\")\n    for svc in result.services[:5]:\n        banner = f'\"{svc.banner[:30]}...\"' if svc.banner else '\"\"'\n        print(f\"{svc.port},{svc.service_name or 'unknown'},{svc.version or 'N/A'},{svc.protocol},{banner}\")\n    \n    if len(result.services) > 5:\n        print(f\"... and {len(result.services) - 5} more services\")\n    \n    return result\n\ndef demo_network_sweep():\n    \"\"\"Demo: Network segment scanning simulation\"\"\"\n    print_section(\"Advanced Demo 7: Network Sweep Simulation\")\n    \n    print(\"Simulating network sweep of subnet 192.168.1.0/24...\\n\")\n    \n    # Simulate scanning multiple IPs\n    simulated_hosts = [\n        {\"ip\": \"192.168.1.1\", \"ports\": [22, 80, 443]},\n        {\"ip\": \"192.168.1.50\", \"ports\": [3306, 5432]},\n        {\"ip\": \"192.168.1.100\", \"ports\": [22, 80]},\n        {\"ip\": \"192.168.1.200\", \"ports\": [445]},\n    ]\n    \n    print(\"Network Hosts Found:\")\n    print(\"-\" * 70)\n    print(f\"{'Host IP':<20} {'Open Ports':<20} {'Services'}\")\n    print(\"-\" * 70)\n    \n    for host in simulated_hosts:\n        services = \", \".join(map(str, host['ports']))\n        print(f\"{host['ip']:<20} {len(host['ports']):<20} {services}\")\n    \n    # Summary\n    total_hosts = len(simulated_hosts)\n    total_ports = sum(len(h['ports']) for h in simulated_hosts)\n    avg_ports = total_ports / total_hosts if total_hosts > 0 else 0\n    \n    print(\"\\nNetwork Summary:\")\n    print(\"-\" * 70)\n    print(f\"Total Hosts Discovered: {total_hosts}\")\n    print(f\"Total Open Ports:       {total_ports}\")\n    print(f\"Average Ports/Host:     {avg_ports:.1f}\")\n    \n    return simulated_hosts\n\ndef demo_compliance_check():\n    \"\"\"Demo: Security compliance checking\"\"\"\n    print_section(\"Advanced Demo 8: Compliance Check\")\n    \n    scanner = PortScanner(max_threads=100, timeout=2, banner_grab=True)\n    \n    # Define compliance rules\n    compliance_rules = {\n        'no_telnet': {'port': 23, 'allowed': False, 'reason': 'Telnet is insecure'},\n        'ssh_enabled': {'port': 22, 'allowed': True, 'reason': 'SSH should be available'},\n        'https_preferred': {'port': 443, 'allowed': True, 'reason': 'HTTPS recommended'},\n        'no_ftp': {'port': 21, 'allowed': False, 'reason': 'FTP is insecure'},\n    }\n    \n    print(\"Performing compliance check scan...\\n\")\n    result = scanner.scan(\"localhost\", port_range=\"1-1024\")\n    \n    open_ports_set = set(result.open_ports)\n    \n    print(\"Compliance Assessment Results:\")\n    print(\"=\"*70)\n    \n    compliance_status = []\n    \n    for rule_name, rule in compliance_rules.items():\n        port = rule['port']\n        is_open = port in open_ports_set\n        allowed = rule['allowed']\n        \n        if allowed:\n            status = \"✓ PASS\" if is_open else \"✗ FAIL\"\n            message = f\"Port {port} should be open but is {'open' if is_open else 'closed'}\"\n        else:\n            status = \"✓ PASS\" if not is_open else \"✗ FAIL\"\n            message = f\"Port {port} should be closed but is {'open' if is_open else 'closed'}\"\n        \n        compliance_status.append(status)\n        \n        print(f\"{status} | {rule_name.upper()}\")\n        print(f\"    Requirement: {rule['reason']}\")\n        print(f\"    Status: {message}\\n\")\n    \n    # Overall compliance\n    passed = sum(1 for s in compliance_status if 'PASS' in s)\n    total = len(compliance_status)\n    compliance_percent = (passed / total * 100) if total > 0 else 0\n    \n    print(\"=\"*70)\n    print(f\"Overall Compliance: {compliance_percent:.0f}% ({passed}/{total} rules passed)\")\n    \n    return result\n\ndef main():\n    \"\"\"Run advanced demos\"\"\"\n    print(\"\\n\")\n    print(\"╔\" + \"═\"*68 + \"╗\")\n    print(\"║\" + \" \"*15 + \"TracePort - ADVANCED DEMO\" + \" \"*28 + \"║\")\n    print(\"║\" + \" \"*10 + \"Professional Scanning & Analysis Techniques\" + \" \"*15 + \"║\")\n    print(\"╚\" + \"═\"*68 + \"╝\")\n    \n    demos = [\n        (\"1\", \"Service Fingerprinting\", demo_service_fingerprinting),\n        (\"2\", \"Network Topology Mapping\", demo_network_topology),\n        (\"3\", \"Comparative Analysis\", demo_comparative_analysis),\n        (\"4\", \"Vulnerability Assessment\", demo_vulnerability_assessment),\n        (\"5\", \"Performance Analysis\", demo_performance_analysis),\n        (\"6\", \"Multi-Format Export\", demo_batch_export),\n        (\"7\", \"Network Sweep Simulation\", demo_network_sweep),\n        (\"8\", \"Compliance Checking\", demo_compliance_check),\n    ]\n    \n    print(\"\\nAvailable Advanced Demos:\")\n    print(\"-\" * 50)\n    for num, desc, _ in demos:\n        print(f\"  {num}. {desc}\")\n    \n    print(f\"\\n  A. Run All Demos\")\n    print(f\"  Q. Exit\")\n    print(\"-\" * 50)\n    \n    choice = input(\"\\nSelect demo to run (1-8, A, or Q): \").strip().upper()\n    \n    if choice == 'Q':\n        print(\"\\nExiting advanced demo...\")\n        return\n    \n    if choice == 'A':\n        for num, desc, demo_func in demos:\n            try:\n                demo_func()\n            except Exception as e:\n                print(f\"\\nError in {desc}: {str(e)}\")\n            input(\"\\nPress Enter to continue to next demo...\")\n    else:\n        for num, desc, demo_func in demos:\n            if num == choice:\n                try:\n                    demo_func()\n                except Exception as e:\n                    print(f\"\\nError: {str(e)}\")\n                break\n    \n    print_section(\"Advanced Demo Complete!\")\n    print(\"For more information: https://github.com/PasinduW-sketch/TracePort\")\n    print()\n\nif __name__ == \"__main__\":\n    main()\n"